// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.query.algebra.equivalence.CheckOptions;
import org.eclipse.rdf4j.query.algebra.equivalence.ContextMode;
import org.eclipse.rdf4j.query.algebra.equivalence.ObservationMode;
import org.eclipse.rdf4j.query.algebra.equivalence.RuleId;
import org.eclipse.rdf4j.query.algebra.equivalence.SemanticsTarget;
import org.junit.jupiter.api.Test;

class RuleCoverageManifestTest {
	private static final int PROFILE_COUNT = SemanticsTarget.values().length
			* ObservationMode.values().length
			* ContextMode.values().length;

	@Test
	void everyManifestCellMatchesTheExecutableTheoremRegistry() throws IOException {
		List<String> lines = Files.readAllLines(Path.of("formal", "rule-coverage.csv"));
		assertEquals("rule,target,observation,context,status,reference", lines.get(0));
		assertEquals(1 + RuleId.values().length * PROFILE_COUNT, lines.size());

		Set<String> cells = new HashSet<>();
		for (String line : lines.subList(1, lines.size())) {
			String[] columns = line.split(",", 6);
			assertEquals(6, columns.length, line);
			RuleId rule = RuleId.valueOf(columns[0]);
			SemanticsTarget target = target(columns[1]);
			ObservationMode observation = ObservationMode.valueOf(columns[2]);
			ContextMode context = ContextMode.valueOf(columns[3]);
			String cell = rule + "/" + target + "/" + observation + "/" + context;
			assertTrue(cells.add(cell), () -> "Duplicate manifest cell: " + cell);

			CheckOptions options = CheckOptions.builder()
					.semanticsTarget(target)
					.observationMode(observation)
					.contextMode(context)
					.build();
			boolean executableTheorem = rule == RuleId.STRUCTURAL_EQUALITY
					|| CertifiedRuleRegistry.permits(rule, options);
			assertEquals(executableTheorem, columns[4].equals("THEOREM"), line);
			assertFalse(columns[5].isBlank(), line);
		}
		assertEquals(RuleId.values().length * PROFILE_COUNT, cells.size());
	}

	private static SemanticsTarget target(String value) {
		return switch (value) {
		case "RDF4J_RUNTIME" -> SemanticsTarget.RDF4J_RUNTIME;
		case "SPARQL_1_1" -> SemanticsTarget.SPARQL_1_1;
		case "SPARQL_1_2_DRAFT_2026_06_05" -> SemanticsTarget.SPARQL_1_2_DRAFT;
		case "BOTH_1_1_AND_1_2" -> SemanticsTarget.BOTH_1_1_AND_1_2;
		default -> throw new AssertionError("Unknown manifest target: " + value);
		};
	}
}
